function d(c,n,o,a){const t=r=>r*Math.PI/180,e=t(o-c),h=t(a-n),s=Math.sin(e/2)*Math.sin(e/2)+Math.cos(t(c))*Math.cos(t(o))*Math.sin(h/2)*Math.sin(h/2);return 6371*(2*Math.atan2(Math.sqrt(s),Math.sqrt(1-s)))}function f(c,n){const[o,a]=c;let t=!1;for(let i=0,e=n.length-1;i<n.length;e=i,i+=1){const[h,s]=n[i],[r,M]=n[e];s>a!=M>a&&o<(r-h)*(a-s)/(M-s||Number.EPSILON)+h&&(t=!t)}return t}export{d as h,f as i};
